use std::sync::{Arc, Mutex, RwLock};
use std::thread;
use std::collections::HashMap;

#[derive(Debug)]
pub struct InventoryItem {
    pub name: String,
    pub stock: i32,
}

#[derive(Debug)]
pub struct InventoryManager {
    items: Arc<RwLock<HashMap<String, InventoryItem>>>,
}

impl InventoryManager {
    pub fn new() -> Self {
        let items = Arc::new(RwLock::new(HashMap::new()));
        InventoryManager { items }
    }

    pub fn add_item(&self, name: String, stock: i32) {
        let mut items = self.items.write().unwrap();
        items.insert(name, InventoryItem { name, stock });
    }

    pub fn check_stock(&self, item_name: &str) -> Option<i32> {
        let items = self.items.read().unwrap();
        items.get(item_name).map(|item| item.stock)
    }

    pub fn try_decrement_stock(&self, item_name: &str, quantity: i32) -> bool {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(item_name) {
            if item.stock >= quantity {
                item.stock -= quantity;
                return true;
            }
        }
        false
    }
}

pub fn concurrent_inventory_test() {
    let inventory = Arc::new(InventoryManager::new());
    inventory.add_item("laptop".to_string(), 100);
    
    let mut handles = vec![];
    
    for i in 0..10 {
        let inventory_clone = Arc::clone(&inventory);
        let handle = thread::spawn(move || {
            for _ in 0..5 {
                if inventory_clone.try_decrement_stock("laptop", 1) {
                    println!("Thread {} decremented stock", i);
                } else {
                    println!("Thread {} failed to decrement stock", i);
                }
                thread::sleep(std::time::Duration::from_millis(10));
            }
        });
        handles.push(handle);
    }
    
    for handle in handles {
        handle.join().unwrap();
    }
    
    println!("Final stock: {:?}", inventory.check_stock("laptop"));
}